function inRing(lng,lat,r){let c=false;for(let i=0,j=r.length-1;i<r.length;j=i++){const xi=r[i][0],yi=r[i][1],xj=r[j][0],yj=r[j][1];if(((yi>lat)!==(yj>lat))&&(lng<(xj-xi)*(lat-yi)/(yj-yi)+xi))c=!c;}return c;}
export function countyOfPoint(lng,lat){if(typeof lng!=="number"||typeof lat!=="number")return null;for(const c of AZ_COUNTY_POLYS){for(const ring of c.rings)if(inRing(lng,lat,ring))return c.name;}return null;}
